namespace sv_b667b105b6bd4255954d2bac67bc7524.Services;

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> _data = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic Neapolitan pizza with fresh mozzarella, basil, and San Marzano tomatoes.", 30),
            new(2, "Spaghetti Carbonara", "Creamy Roman pasta with guanciale, egg yolk, Pecorino Romano, and black pepper.", 25),
            new(3, "Risotto alla Milanese", "Saffron-infused Arborio rice slowly cooked in broth with butter and Parmigiano.", 45),
            new(4, "Tiramisu", "Layered dessert of espresso-soaked ladyfingers and mascarpone cream dusted with cocoa.", 40),
        },
        [2] = new List<Recipe>
        {
            new(5, "Kung Pao Chicken", "Spicy Sichuan stir-fry with chicken, peanuts, chili peppers, and Sichuan peppercorns.", 35),
            new(6, "Mapo Tofu", "Silken tofu in a fiery, numbing sauce of doubanjiang, ground pork, and fermented black beans.", 20),
            new(7, "Xiaolongbao", "Shanghai-style soup dumplings filled with seasoned pork and rich gelatinized broth.", 90),
        },
        [3] = new List<Recipe>
        {
            new(8, "Tacos al Pastor", "Spit-roasted pork marinated in achiote and pineapple, served on corn tortillas.", 60),
            new(9, "Mole Poblano", "Complex Pueblan sauce of dried chiles, chocolate, spices, and nuts served over turkey.", 120),
            new(10, "Guacamole", "Fresh avocado dip with lime, cilantro, onion, jalapeño, and tomato.", 10),
            new(11, "Elote", "Grilled Mexican street corn with mayo, cotija cheese, chili powder, and lime.", 15),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        // Simulate slow API call
        await Task.Delay(2000, cancellationToken);

        if (_data.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@implements IDisposable
@inject IRecipeService RecipeService
@inject NavigationManager Nav
@inject ILogger<Recipes> Logger

<PageTitle>Recipes</PageTitle>

<h1>Recipes — Cuisine @CuisineId</h1>

@if (_error is not null)
{
    <div class="alert alert-danger d-flex align-items-center justify-content-between" role="alert">
        <span>@_error</span>
        <button class="btn btn-outline-danger btn-sm ms-3" @onclick="Retry">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes…</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <div class="alert alert-info py-1 px-3" role="status">Refreshing…</div>
    }

    <div class="mb-3">
        <label class="form-label fw-semibold">Sort by:</label>
        <a href="@GetSortUrl("newest")" class="btn btn-sm @(ActiveSort == "newest" ? "btn-primary" : "btn-outline-primary") me-1">Newest</a>
        <a href="@GetSortUrl("popular")" class="btn btn-sm @(ActiveSort == "popular" ? "btn-primary" : "btn-outline-primary")">Popular</a>
    </div>

    @if (_recipes.Count == 0)
    {
        <p>No recipes found for this cuisine.</p>
    }
    else
    {
        <div class="row">
            @foreach (var recipe in SortedRecipes)
            {
                <div class="col-md-6 col-lg-4 mb-3">
                    <div class="card h-100">
                        <div class="card-body">
                            <h5 class="card-title">@recipe.Title</h5>
                            <p class="card-text">@recipe.Description</p>
                        </div>
                        <div class="card-footer text-body-secondary">
                            🕐 @recipe.PrepTimeMinutes min
                        </div>
                    </div>
                </div>
            }
        </div>
    }
}

@code {
    [Parameter] public int CuisineId { get; set; }
    [SupplyParameterFromQuery(Name = "sort")] public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private string? _error;
    private bool _isRefreshing;
    private int _loadedCuisineId;

    private CancellationTokenSource? _cts;
    private readonly CancellationTokenSource _disposeCts = new();

    private string ActiveSort => string.Equals(Sort, "popular", StringComparison.OrdinalIgnoreCase)
        ? "popular"
        : "newest";

    private IEnumerable<Recipe> SortedRecipes => ActiveSort == "popular"
        ? _recipes!.OrderBy(r => r.PrepTimeMinutes)
        : _recipes!.OrderByDescending(r => r.Id);

    protected override Task OnParametersSetAsync()
    {
        if (CuisineId != _loadedCuisineId)
        {
            return LoadRecipesAsync();
        }

        // Sort-only change — no reload needed, just re-render.
        return Task.CompletedTask;
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request for a previous cuisine.
        await CancelPendingLoadAsync();

        _error = null;
        _isRefreshing = _recipes is not null;
        var targetCuisineId = CuisineId;

        using var cts = CancellationTokenSource.CreateLinkedTokenSource(_disposeCts.Token);
        _cts = cts;

        try
        {
            var result = await RecipeService.GetByCuisineAsync(targetCuisineId, cts.Token);

            _recipes = result;
            _loadedCuisineId = targetCuisineId;
        }
        catch (OperationCanceledException) when (cts.IsCancellationRequested)
        {
            // Load was intentionally cancelled (navigation away or cuisine change). Do nothing.
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", targetCuisineId);
            _error = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", targetCuisineId);
            _error = "Something went wrong while loading recipes. Please try again.";
        }
        finally
        {
            if (ReferenceEquals(_cts, cts))
            {
                _cts = null;
            }

            _isRefreshing = false;
        }
    }

    private async Task CancelPendingLoadAsync()
    {
        if (_cts is { } pending)
        {
            await pending.CancelAsync();
            _cts = null;
        }
    }

    private Task Retry() => LoadRecipesAsync();

    private string GetSortUrl(string sort) => Nav.GetUriWithQueryParameter("sort", sort);

    public void Dispose()
    {
        _disposeCts.Cancel();
        _disposeCts.Dispose();
        _cts = null;
    }
}

